// Robust reheader + filter full rows

const CLEAN = v => {
  if (v == null) return '';
  const s = String(v).replace(/\r?\n/g, ' ').replace(/\s+/g, ' ').trim();
  if (s.toLowerCase() === 'undefined' || s.toLowerCase() === 'empty') return '';
  return s;
};

const rows = items.map(i => i.json);

// 1) Tìm dòng header: có cả "STT" và "Mã sản phẩm"
let headerIdx = -1;
for (let i = 0; i < rows.length; i++) {
  const vals = Object.values(rows[i]).map(CLEAN);
  const hasSTT = vals.some(v => /stt/i.test(v));
  const hasSKU = vals.some(v => /mã\s*sản\s*phẩm.*sku/i.test(v));
  if (hasSTT && hasSKU) { headerIdx = i; break; }
}
if (headerIdx < 0) {
  throw new Error('Không tìm thấy dòng tiêu đề chứa "STT" và "Mã sản phẩm".');
}

// 2) Lấy tiêu đề
const headerRow = rows[headerIdx];
const origKeys  = Object.keys(headerRow);
const headers = origKeys.map(k => CLEAN(headerRow[k]));

// Bỏ các cột header rỗng / __EMPTY
const keepIdx = headers
  .map((h, i) => ({ h, i }))
  .filter(x => x.h && !/^_+empty/i.test(x.h.replace(/\s/g,'')))
  .map(x => x.i);

// 3) Duyệt dữ liệu sau header
const out = [];
for (let r = headerIdx + 1; r < rows.length; r++) {
  const row = rows[r] || {};
  const obj = {};
  for (const i of keepIdx) {
    const colName = headers[i];
    obj[colName] = CLEAN(row[origKeys[i]]);
  }

  // a) tất cả ô đều có giá trị
  const allFilled = Object.values(obj).length > 0 && Object.values(obj).every(v => v !== '');

  // b) STT phải là số (loại các dòng nhóm "Laptop - ...")
  const sttKey = headers.find(h => /stt/i.test(h)) || 'STT';
  const sttOk = /^\d+$/.test(obj[sttKey] || '');

  if (allFilled && sttOk) out.push({ json: obj });
}

return out;

// Chỉ lấy ra SKU từ các item hiện tại
// - Giữ nguyên thứ tự & giữ duplicate
// - Tự dò tên cột: chứa "sku" hoặc "mã sản phẩm"

const clean = v => (v == null ? '' : String(v).trim());

if (!items.length) return [];

const keys = Object.keys(items[0].json).map(k => k.trim());

// Ưu tiên cột có chữ "sku"
let skuKey = keys.find(k => /(^|\W)sku(\W|$)/i.test(k));
// Nếu không có, thử "mã sản phẩm"
if (!skuKey) skuKey = keys.find(k => /mã\s*sản\s*phẩm/i.test(k));

if (!skuKey) {
  throw new Error('Không tìm thấy cột SKU (tiêu đề có "SKU" hoặc "Mã sản phẩm").');
}

const out = [];
for (const it of items) {
  const sku = clean(it.json[skuKey]);
  if (sku) out.push({ json: { sku } });
}

return out;

// Input: items là các dòng đã join, mỗi dòng đại diện 1 (sku, bin_code)
// Ta chỉ cần sku để ghép chuỗi cuối:
return items.map(it => ({ json: { sku: it.json['Mã sản phẩm'], bin: it.json['Mã Bin'] }}));

// Input: items = [{ json: { sku, bin } }, ... ]
// Rule: số lần "xuất hiện" của 1 SKU = số BIN KHÁC NHAU của SKU đó.
// Lặp theo: k -> 1 + 10*(k-1)  (1->1, 2->11, 3->21, ...)
// Trả ra: { joined, count }  với count = số SKU (distinct) trước khi join.

const norm = v => String(v ?? '').trim().toUpperCase();

// 1) Gom BIN theo SKU
const skuBins = new Map();   // sku -> Set(bin)
const order = [];            // thứ tự gặp SKU lần đầu

for (const it of items) {
  const sku = norm(it?.json?.sku);
  const bin = norm(it?.json?.bin);
  if (!sku) continue;

  if (!skuBins.has(sku)) { skuBins.set(sku, new Set()); order.push(sku); }
  if (bin) skuBins.get(sku).add(bin);           // cùng bin chỉ tính 1 lần
  else     skuBins.get(sku).add('');            // thiếu bin -> gộp như một bin rỗng
}

// 2) Expand theo quy tắc
const out = [];
for (const sku of order) {
  const distinctBins = skuBins.get(sku).size;   // k
  const rep = 1 + 10 * (distinctBins - 1);      // 1, 11, 21, ...
  for (let i = 0; i < rep; i++) out.push(sku);
}

// 3) Kết quả
return [{
  json: {
    joined: out.join(','),
    count: order.length,       // số SKU distinct trước khi join
    expanded_count: out.length // nếu cần kiểm soát
  }
}];

